import{_ as t,W as o,X as c,Z as n,$ as a,a0 as s,a1 as i,D as l}from"./framework-c9619a7b.js";const p={},d=i(`<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>Minio是一款开源的对象存储服务器，可以在自己的服务器上免费部署，相比于付费的云存储服务，成本更低。使用Minio搭建个人图床，用户可以完全控制自己的数据，而不必将其存储在第三方服务提供商的服务器上，从而保护自己的隐私和数据安全。</p><p>PicGo是一款基于Electron的开源图片上传工具，可以方便地将本地图片上传到云存储或者自建图床。它支持多种图床，如七牛云、腾讯云、阿里云等，同时也支持自定义图床。PicGo的特点是可以自定义快捷键、自动压缩图片、支持截图上传、支持拖拽上传等功能，简单易用。PicGo也支持插件，用户可以自由地扩展功能。PicGo还有一个图床分发中心，用户可以在中心下载其他用户共享的图床配置，方便快捷。</p><p>将这两个工具结合，可以得到一个方便易用、注重隐私和安全、不用担心跑路的个人图床搭建方案。</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2><h3 id="minio" tabindex="-1"><a class="header-anchor" href="#minio" aria-hidden="true">#</a> Minio</h3><h4 id="拉取镜像-运行容器" tabindex="-1"><a class="header-anchor" href="#拉取镜像-运行容器" aria-hidden="true">#</a> 拉取镜像，运行容器</h4><p><code>docker-compose.yaml</code>如下：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token string">&quot;3.9&quot;</span>

<span class="token key atrule">services</span><span class="token punctuation">:</span>
  <span class="token key atrule">minio</span><span class="token punctuation">:</span>
    <span class="token key atrule">image</span><span class="token punctuation">:</span> minio/minio<span class="token punctuation">:</span>latest
    <span class="token key atrule">container_name</span><span class="token punctuation">:</span> minio
    <span class="token key atrule">restart</span><span class="token punctuation">:</span> unless<span class="token punctuation">-</span>stopped <span class="token comment"># always</span>
    
    <span class="token key atrule">environment</span><span class="token punctuation">:</span>
      <span class="token key atrule">MINIO_ROOT_USER</span><span class="token punctuation">:</span> user
      <span class="token key atrule">MINIO_ROOT_PASSWORD</span><span class="token punctuation">:</span> pass
    <span class="token comment"># 数据卷设置</span>
    <span class="token key atrule">volumes</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> $<span class="token punctuation">{</span>PWD<span class="token punctuation">}</span>/data<span class="token punctuation">:</span>/data
      <span class="token punctuation">-</span> $<span class="token punctuation">{</span>PWD<span class="token punctuation">}</span>/config<span class="token punctuation">:</span>/root/.minio
    
    <span class="token comment"># 端口映射</span>
    <span class="token key atrule">ports</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> 9000<span class="token punctuation">:</span><span class="token number">9000</span>
      <span class="token punctuation">-</span> 9001<span class="token punctuation">:</span><span class="token number">9001</span>
    <span class="token key atrule">command</span><span class="token punctuation">:</span> <span class="token string">&#39;server /data --console-address &quot;:9001&quot;&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>启动：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> compose up <span class="token parameter variable">-d</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="配置" tabindex="-1"><a class="header-anchor" href="#配置" aria-hidden="true">#</a> 配置</h4><ul><li>创建存储桶</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/Snipaste_2023-04-27_13-29-34.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>这里设置的图床名称为<code>image-bed</code>。</p><figure><img src="https://minio.kevin2li.top/image-bed/20230427143555.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li>设置存储桶访问权限</li></ul><p>默认新建的存储桶访问策略为<code>privete</code>，但是作为图床使用需要将其设置为<code>public</code>，其他人才能访问。</p><figure><img src="https://minio.kevin2li.top/image-bed/20230427142129.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li>创建<code>access key</code></li></ul><figure><img src="https://minio.kevin2li.top/image-bed/Snipaste_2023-04-27_13-30-31.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="https://minio.kevin2li.top/image-bed/Snipaste_2023-04-27_13-31-52.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>下载保存生成的<code>access key</code>和<code>secret key</code></p><figure><img src="https://minio.kevin2li.top/image-bed/Snipaste_2023-04-27_13-32-44.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="公网访问" tabindex="-1"><a class="header-anchor" href="#公网访问" aria-hidden="true">#</a> 公网访问</h3><h4 id="nps隧道搭建" tabindex="-1"><a class="header-anchor" href="#nps隧道搭建" aria-hidden="true">#</a> nps隧道搭建</h4><p>由于我的minio对象存储服务搭建在本地机器上，需要将其通过内网穿透使其可以公网访问。</p>`,27),r={href:"https://github.com/ehang-io/nps",target:"_blank",rel:"noopener noreferrer"},u=n("code",null,"9001",-1),m=n("code",null,"9200",-1),h=i(`<figure><img src="https://minio.kevin2li.top/image-bed/20230427144720.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>注：同时要在云服务器开放<code>9200</code>端口</p><h4 id="caddy反向代理" tabindex="-1"><a class="header-anchor" href="#caddy反向代理" aria-hidden="true">#</a> caddy反向代理</h4><p>在<code>/etc/caddy/Caddyfile</code>中加入下面配置：</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code>minio.example.com <span class="token punctuation">{</span>
    encode gzip
    reverse_proxy <span class="token number">127.0</span>.<span class="token number">0.1</span><span class="token operator">:</span><span class="token number">9200</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>重启caddy服务：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> systemctl restart caddy
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="子域名配置" tabindex="-1"><a class="header-anchor" href="#子域名配置" aria-hidden="true">#</a> 子域名配置</h4>`,8),g=n("code",null,"minio.example.com",-1),k={href:"https://github.com/NewFuture/DDNS",target:"_blank",rel:"noopener noreferrer"},v=i(`<div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>ddns <span class="token parameter variable">--id</span> <span class="token operator">&lt;</span>your_id<span class="token operator">&gt;</span> <span class="token parameter variable">--token</span> <span class="token operator">&lt;</span>your_token<span class="token operator">&gt;</span> <span class="token parameter variable">--index4</span> <span class="token string">&quot;public&quot;</span> <span class="token parameter variable">--dns</span> <span class="token string">&quot;dnspod&quot;</span> <span class="token parameter variable">--ipv4</span> <span class="token string">&quot;minio.example.com&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="picgo" tabindex="-1"><a class="header-anchor" href="#picgo" aria-hidden="true">#</a> PicGo</h3><h4 id="安装minio插件" tabindex="-1"><a class="header-anchor" href="#安装minio插件" aria-hidden="true">#</a> 安装minio插件</h4><p>在插件设置中，搜索<code>minio</code>插件，点击安装即可。</p><figure><img src="https://minio.kevin2li.top/image-bed/20230427144902.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h4 id="配置minio图床" tabindex="-1"><a class="header-anchor" href="#配置minio图床" aria-hidden="true">#</a> 配置minio图床</h4><p>安装完成后，图床设置板块会多出一个MinIO图床，点击进行相关配置。</p><ul><li><code>endPoint</code>: 填写公网服务器的IP</li><li><code>port</code>: 填写minio服务的端口</li><li><code>accessKey</code>: 之前下载保存的文件里有</li><li><code>secretKey</code>:之前下载保存的文件里有</li><li><code>bucket</code>: 存储桶名称</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/20230427145101.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p><img src="https://minio.kevin2li.top/image-bed/20230427145151.png" alt="" loading="lazy"> 填写完成后，确定即可生效。然后可以在上传区上传一张图片测试一下效果。</p><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>`,11),b={href:"https://juejin.cn/post/7203258813893345340",target:"_blank",rel:"noopener noreferrer"},f={href:"https://www.cnblogs.com/mikemhm/p/16160988.html",target:"_blank",rel:"noopener noreferrer"};function _(y,x){const e=l("ExternalLinkIcon");return o(),c("div",null,[d,n("p",null,[a("本文通过"),n("a",r,[a("nps"),s(e)]),a("这一内网穿透工具实现隧道搭建，将本地的"),u,a("端口映射到公网云服务器的"),m,a("端口。")]),h,n("p",null,[a("由于上面使用"),g,a("作为域名，需要在云服务厂商的域名控制台新建这个子域名，也可以使用"),n("a",k,[a("ddns"),s(e)]),a("快速配置：")]),v,n("ol",null,[n("li",null,[n("a",b,[a("掘金------Docker 搭建 Minio 对象存储服务"),s(e)])]),n("li",null,[n("a",f,[a("博客园------PicGo minio 图床"),s(e)])])])])}const z=t(p,[["render",_],["__file","使用Minio与Picgo搭建个人图床.html.vue"]]);export{z as default};
